SELECT *
FROM market_prediction
WHERE market_id = #{marketId}
  AND member_id = #{memberId}

SELECT *
FROM market_prediction
WHERE market_id = #{marketId}
  AND member_id = #{memberId}
FOR UPDATE

mapper.update:
UPDATE market
SET total_pool = total_pool + #{pointAmount},
    updated_at = #{updatedAt}
WHERE id = #{marketId}
  AND deleted_at IS NULL

UPDATE market_option
SET real_pool_amount = #{realPoolAmount},
    total_contract_quantity = #{totalContractQuantity},
    current_price = #{currentPrice},
    prediction_count = #{predictionCount},
    updated_at = #{updatedAt}
WHERE id = #{id}
  AND market_id = #{marketId}

UPDATE market_prediction
SET status = #{status},
    fail_reason = #{failReason},
    updated_at = #{updatedAt}
WHERE id = #{predictionId}
  AND status = 'POINT_PENDING'
